/**
 * Safe emit wrapper — runs the public-safe gate, suppresses on failure
 * and emits a clean fallback event instead. Returns true if the original
 * was emitted, false if it was rejected.
 */
function safeEmit(emit: EmitFn, ev: AgentEvent, expectedToolUsage: boolean): boolean {
  const guard = checkAgentEventSafe(ev, { expectedToolUsage });
  if (!guard.ok) {
