  brain2Result?: string;
  coordinatorAction?: string;
  cycle: TaskCycle[];
}

export interface TaskCycle {
  timestamp: string;
  phase: "analyze" | "summarize" | "coordinate" | "commit" | "push" | "review" | "memory";
