    const a = Array.isArray(base[k]) ? (base[k] as string[]) : [];
    const b = Array.isArray(overlay[k]) ? (overlay[k] as string[]) : [];
    if (a.length === 0 && b.length === 0) continue;
    out[k] = Array.from(new Set([...a, ...b].map((x) => String(x).trim()).filter(Boolean)));
