export type RiskLevel = "low" | "medium" | "high" | "critical";

export interface RiskAssessment {
  riskLevel: RiskLevel;
  reason: string;
  requiresApproval: boolean;
}

// Patterns that require approval
const CRITICAL_PATTERNS = [
  /rm\s+-rf?\s+[\/~]/i,
  /format\s+(c:|d:|\/dev\/)/i,
  /mkfs/i,
  /dd\s+if=/i,
  />\s*\/dev\/(sd|hd|vd)/i,
];

const HIGH_PATTERNS = [
